import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core
from src.utils.prism_config import (
    resolve_cfg, get_departments, resolve_dept_name, get_entity_scenefiles_root
)

class PrismGetDepartmentsNode(BaseNode):
    name = "Prism: Get Departments"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_output("departments", "list")
        self.add_output("abbreviations", "list")
        self.add_output("default_tasks", "list")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        if core is None:
            self.log_error('No PrismCore found.')
            return {'departments': [], 'abbreviations': [], 'default_tasks': [], 'count': 0}
        cfg_path = resolve_cfg(core=core, entity=entity)
        entity_type = entity.get('type', 'shot')
        dept_defs = get_departments(core, cfg_path, entity_type)
        if dept_defs:
            self.log_info(f'departments from pipeline.json ({cfg_path}): {[(d["abbreviation"], d["name"]) for d in dept_defs]}')
            names = [d['name'] for d in dept_defs]
            abbrevs = [d['abbreviation'] for d in dept_defs]
            default_tasks = [d['defaultTasks'] for d in dept_defs]
            return {'departments': names, 'abbreviations': abbrevs, 'default_tasks': default_tasks, 'count': len(names)}
        scenes_root = get_entity_scenefiles_root(entity, core, cfg_path)
        if not scenes_root:
            self.log_error(f"No Scenefiles folder found for entity path '{entity.get('path', '')}'")
            return {'departments': [], 'abbreviations': [], 'default_tasks': [], 'count': 0}
        abbrevs = sorted(e.name for e in os.scandir(scenes_root) if e.is_dir())
        names = [resolve_dept_name(a, dept_defs) for a in abbrevs]
        self.log_info(f'departments from disk ({scenes_root}): {list(zip(abbrevs, names))}')
        return {'departments': names, 'abbreviations': abbrevs, 'default_tasks': [[] for _ in abbrevs], 'count': len(names)}

def register_node():
    return PrismGetDepartmentsNode
